"use strict";(self.webpackChunkmuvee_docs=self.webpackChunkmuvee_docs||[]).push([[563],{7073(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"category","label":"Getting Started","items":[{"type":"link","label":"Getting Started","href":"/muvee/docs/getting-started","docId":"getting-started","unlisted":false},{"type":"link","label":"Installation","href":"/muvee/docs/installation","docId":"installation","unlisted":false},{"type":"link","label":"Configuration Reference","href":"/muvee/docs/configuration","docId":"configuration","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Authentication","items":[{"type":"link","label":"Google OAuth2","href":"/muvee/docs/auth/auth-google","docId":"auth/auth-google","unlisted":false},{"type":"link","label":"Feishu / Lark","href":"/muvee/docs/auth/auth-feishu","docId":"auth/auth-feishu","unlisted":false},{"type":"link","label":"WeCom (\u4f01\u4e1a\u5fae\u4fe1)","href":"/muvee/docs/auth/auth-wecom","docId":"auth/auth-wecom","unlisted":false},{"type":"link","label":"DingTalk (\u9489\u9489)","href":"/muvee/docs/auth/auth-dingtalk","docId":"auth/auth-dingtalk","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Architecture","items":[{"type":"link","label":"Architecture","href":"/muvee/docs/architecture","docId":"architecture","unlisted":false},{"type":"link","label":"Scheduler & Affinity","href":"/muvee/docs/scheduler","docId":"scheduler","unlisted":false},{"type":"link","label":"Dataset Monitor","href":"/muvee/docs/dataset-monitor","docId":"dataset-monitor","unlisted":false},{"type":"link","label":"ForwardAuth & Project Access Control","href":"/muvee/docs/forward-auth","docId":"forward-auth","unlisted":false},{"type":"link","label":"Service Auth Integration","href":"/muvee/docs/service-auth-integration","docId":"service-auth-integration","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Operations","items":[{"type":"link","label":"Agent Nodes","href":"/muvee/docs/agents","docId":"agents","unlisted":false},{"type":"link","label":"Traefik Routing","href":"/muvee/docs/traefik","docId":"traefik","unlisted":false},{"type":"link","label":"Secrets Management","href":"/muvee/docs/secrets","docId":"secrets","unlisted":false},{"type":"link","label":"Auto Deploy","href":"/muvee/docs/auto-deploy","docId":"auto-deploy","unlisted":false},{"type":"link","label":"Upgrading","href":"/muvee/docs/upgrade","docId":"upgrade","unlisted":false},{"type":"link","label":"muveectl CLI","href":"/muvee/docs/muveectl","docId":"muveectl","unlisted":false},{"type":"link","label":"AI Agent Integration","href":"/muvee/docs/ai-agent","docId":"ai-agent","unlisted":false}],"collapsed":true,"collapsible":true}]},"docs":{"agents":{"id":"agents","title":"Agent Nodes","description":"A single muvee-agent binary handles both builder and deploy roles. The role is determined by the NODE_ROLE environment variable.","sidebar":"tutorialSidebar"},"ai-agent":{"id":"ai-agent","title":"AI Agent Integration","description":"This guide explains how to let a cloud-hosted AI agent \u2014 or any long-running automation \u2014 call muveectl (and the underlying Muvee API) on behalf of multiple end users, each with a distinct identity.","sidebar":"tutorialSidebar"},"architecture":{"id":"architecture","title":"Architecture","description":"Overview","sidebar":"tutorialSidebar"},"auth/auth-dingtalk":{"id":"auth/auth-dingtalk","title":"DingTalk (\u9489\u9489)","description":"muvee supports sign-in via DingTalk (\u9489\u9489) using the standard OAuth2 authorization code flow. Users are redirected to the DingTalk login page and authenticate with their DingTalk credentials.","sidebar":"tutorialSidebar"},"auth/auth-feishu":{"id":"auth/auth-feishu","title":"Feishu / Lark","description":"muvee supports sign-in via Feishu (\u98de\u4e66, mainland China) and its international counterpart Lark using the Feishu OAuth2 flow.","sidebar":"tutorialSidebar"},"auth/auth-google":{"id":"auth/auth-google","title":"Google OAuth2","description":"muvee supports Google sign-in via OpenID Connect (OIDC). This is the simplest option for teams that already use Google Workspace or personal Google accounts.","sidebar":"tutorialSidebar"},"auth/auth-wecom":{"id":"auth/auth-wecom","title":"WeCom (\u4f01\u4e1a\u5fae\u4fe1)","description":"muvee supports enterprise WeChat Work (WeCom / \u4f01\u4e1a\u5fae\u4fe1) sign-in via the QR-code SSO flow. Users scan a QR code with the WeCom mobile app or the WeCom desktop client to log in \u2014 no password entry required.","sidebar":"tutorialSidebar"},"auto-deploy":{"id":"auto-deploy","title":"Auto Deploy","description":"muvee can redeploy a project automatically when its source moves on. Two","sidebar":"tutorialSidebar"},"configuration":{"id":"configuration","title":"Configuration Reference","description":"All configuration is via environment variables.","sidebar":"tutorialSidebar"},"dataset-monitor":{"id":"dataset-monitor","title":"Dataset Monitor","description":"The Dataset Monitor tracks changes to NFS-backed datasets with file-level granularity \u2014 similar to git log --follow for data files.","sidebar":"tutorialSidebar"},"forward-auth":{"id":"forward-auth","title":"ForwardAuth & Project Access Control","description":"muvee supports per-project authentication for deployed applications. When enabled, any visitor to .domain.com is first redirected to sign in via whichever OAuth provider you have configured (Google, Feishu, WeCom, DingTalk, etc.).","sidebar":"tutorialSidebar"},"getting-started":{"id":"getting-started","title":"Getting Started","description":"muvee is a lightweight self-hosted PaaS that turns any private cloud into a container deployment platform \u2014 with built-in data warehouse integration, LRU-cached dataset injection, and flexible identity provider support.","sidebar":"tutorialSidebar"},"install-agent":{"id":"install-agent","title":"Agent Installation","description":"A muvee agent runs on a worker node and polls the control plane for build or deploy tasks. This guide walks through setting up a brand-new machine \u2014 from installing dependencies to registering the node in the cluster \u2014 for Linux, macOS, and Windows."},"installation":{"id":"installation","title":"Installation","description":"Option A: Docker Compose (Recommended)","sidebar":"tutorialSidebar"},"muveectl":{"id":"muveectl","title":"muveectl CLI","description":"muveectl is the command-line client for Muvee. It lets you manage projects, datasets, and API tokens from your local machine without opening the web UI.","sidebar":"tutorialSidebar"},"scheduler":{"id":"scheduler","title":"Scheduler & Affinity","description":"When a deployment is triggered, muvee must choose which deploy node to run the container on. The scheduler uses an affinity scoring system that balances dataset cache hits, available storage, and node load.","sidebar":"tutorialSidebar"},"secrets":{"id":"secrets","title":"Secrets Management","description":"Muvee provides a built-in Secrets store for safely managing passwords, API tokens, and SSH private keys. Secrets are encrypted at rest using AES-256-GCM and are injected into deployments at runtime.","sidebar":"tutorialSidebar"},"service-auth-integration":{"id":"service-auth-integration","title":"Service Auth Integration","description":"This guide is for developers who deploy services on muvee and want to leverage muvee\'s built-in authentication. When a project has Require Auth enabled, muvee handles the entire OAuth login flow \u2014 your service receives authenticated requests with user identity already resolved.","sidebar":"tutorialSidebar"},"traefik":{"id":"traefik","title":"Traefik Routing","description":"muvee uses Traefik v3 as the reverse proxy.","sidebar":"tutorialSidebar"},"upgrade":{"id":"upgrade","title":"Upgrading","description":"Control Plane","sidebar":"tutorialSidebar"}}}}')}}]);